Sure! Here’s a simple test code for the ESP32 that sets up a basic Wi-Fi connection and prints the IP address. This is a good starting point to check if your ESP32 is working correctly.

```cpp
#include <WiFi.h>

const char* ssid = "your_SSID";     // Replace with your network SSID
const char* password = "your_PASSWORD"; // Replace with your network password

void setup() {
  Serial.begin(115200);
  WiFi.begin(ssid, password);

  Serial.print("Connecting to WiFi");
  while (WiFi.status() != WL_CONNECTED) {
    delay(1000);
    Serial.print(".");
  }

  Serial.println("\nConnected to WiFi");
  Serial.print("IP Address: ");
  Serial.println(WiFi.localIP());
}

void loop() {
  // Add your main code here
}
```

Make sure to replace `your_SSID` and `your_PASSWORD` with your actual Wi-Fi credentials. Would you like me to explain any part of the code or help you with something else?
